#!/usr/bin/env node

/**
 * Organize OpenViking resources into a structured hierarchy.
 *
 * Creates:
 *   viking://resources/hydra/config/agents/    — agent personality files
 *   viking://resources/hydra/config/direction/  — vision, priorities, goals
 *   viking://resources/hydra/config/feedback/   — agent feedback
 *   viking://resources/hydra/research/          — research papers and findings
 *
 * Uses OV's add-resource API with explicit `to` URIs for proper hierarchy.
 * The L0/L1/L2 tiering (abstract/overview/detail) is auto-generated by OV.
 */

import { readdir } from "node:fs/promises";
import { join, resolve } from "node:path";

const OV_URL = process.env.OPENVIKING_URL || "http://localhost:1933";
const OV_KEY = process.env.OPENVIKING_API_KEY || "1080bb34205409e58aa433512cb5e5d6344560adce963c442543001808181115";
const CONFIG_PATH = process.env.HYDRA_CONFIG_PATH || resolve(process.env.HOME, "hydra", "config");

let indexed = 0;
let failed = 0;

async function indexFile(filePath, targetUri) {
  // Copy into OV container first
  const { execFile } = await import("node:child_process");
  const { promisify } = await import("node:util");
  const exec = promisify(execFile);

  const containerPath = `/tmp/ov-import-${Date.now()}.md`;
  await exec("docker", ["cp", filePath, `hydra-openviking-1:${containerPath}`], { timeout: 5000 });

  try {
    const res = await fetch(`${OV_URL}/api/v1/resources`, {
      method: "POST",
      headers: { "Content-Type": "application/json", "X-Api-Key": OV_KEY },
      body: JSON.stringify({
        path: containerPath,
        to: targetUri,
        wait: false, // async — don't block
      }),
      signal: AbortSignal.timeout(10000),
    });
    if (res.ok) {
      indexed++;
      console.log(`  OK  ${targetUri}`);
    } else {
      const text = await res.text().catch(() => "");
      // "file exists" is fine — already indexed
      if (text.includes("file exists")) {
        console.log(`  SKIP ${targetUri} (already exists)`);
      } else {
        failed++;
        console.error(`  FAIL ${targetUri}: ${text.slice(0, 150)}`);
      }
    }
  } catch (err) {
    failed++;
    console.error(`  FAIL ${targetUri}: ${err.message}`);
  }
}

async function indexDirectory(dirPath, baseUri) {
  let files;
  try {
    files = await readdir(dirPath);
  } catch {
    return;
  }

  for (const file of files) {
    if (!file.endsWith(".md")) continue;
    const name = file.replace(".md", "");
    await indexFile(join(dirPath, file), `${baseUri}/${name}`);
  }
}

async function main() {
  console.log("=== Organizing OpenViking resources ===\n");

  console.log("Config: agents");
  await indexDirectory(join(CONFIG_PATH, "agents"), "viking://resources/hydra/config/agents");

  console.log("\nConfig: direction");
  await indexDirectory(join(CONFIG_PATH, "direction"), "viking://resources/hydra/config/direction");

  console.log("\nConfig: feedback");
  await indexDirectory(join(CONFIG_PATH, "feedback"), "viking://resources/hydra/config/feedback");

  console.log("\nConfig: research");
  await indexDirectory(join(CONFIG_PATH, "research"), "viking://resources/hydra/config/research");

  console.log(`\n=== Done. Indexed: ${indexed}, Failed: ${failed} ===`);
}

main().catch(err => {
  console.error("Failed:", err);
  process.exit(1);
});
